"use strict";exports.id=2721,exports.ids=[2721],exports.modules={2721:a=>{a.exports=JSON.parse('{"title":"Acerca de Wayfera","subtitle":"Tu socio de confianza en la creaci\xf3n de experiencias de viaje inolvidables alrededor del mundo","story":{"title":"Nuestra Historia","p1":"Fundada en 2010, Wayfera comenz\xf3 con una misi\xf3n simple: hacer que las experiencias de viaje de clase mundial sean accesibles para todos. Lo que comenz\xf3 como un peque\xf1o equipo de viajeros apasionados ha crecido hasta convertirse en una red global de expertos en viajes.","p2":"A lo largo de los a\xf1os, hemos ayudado a miles de viajeros a descubrir destinos incre\xedbles, crear recuerdos duraderos y experimentar culturas de todo el mundo.","p3":"Hoy, continuamos innovando y expandiendo nuestros servicios, siempre manteniendo los sue\xf1os y la satisfacci\xf3n de nuestros clientes en el coraz\xf3n de todo lo que hacemos."},"values":{"title":"Nuestros Valores","excellence":{"title":"Excelencia","description":"Nos esforzamos por la excelencia en cada viaje que creamos"},"customerFirst":{"title":"Cliente Primero","description":"Tu satisfacci\xf3n es nuestra m\xe1xima prioridad"},"globalReach":{"title":"Alcance Global","description":"Conect\xe1ndote con destinos en todo el mundo"},"passion":{"title":"Pasi\xf3n","description":"Amamos lo que hacemos y se nota"}},"stats":{"countries":"Pa\xedses","clients":"Clientes Felices","destinations":"Destinos","support":"Soporte"}}')}};